// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedDay, setSelectedDay] = useState<string>('');

  const conditionIcon = useMemo(() => {
    const normalized = props.condition.toLowerCase();
    if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloud')) return '☁️';
    if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('snow') || normalized.includes('sleet')) return '❄️';
    if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    return '🌤️';
  }, [props.condition]);

  const resolvedUnit = props.unit === 'F' ? 'F' : 'C';
  const displayedForecast = useMemo(() => {
    const limited = (props.forecast || []).slice(0, 5);
    const placeholdersNeeded = Math.max(0, 5 - limited.length);
    const placeholders = Array.from({ length: placeholdersNeeded }, (_, index) => ({
      day: `Day ${limited.length + index + 1}`,
      icon: '🌤️',
      high: undefined,
      low: undefined,
    }));
    return [...limited, ...placeholders];
  }, [props.forecast]);

  useEffect(() => {
    if (!selectedDay && displayedForecast.length > 0) {
      setSelectedDay(displayedForecast[0]?.day || '');
    }
  }, [displayedForecast, selectedDay]);
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          radius="xl"
          border
        >
          <Stack gap="var(--ggui-spacing-6)">
            <Row justify="between" align="start" wrap>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Current Weather
                </Text>
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  {props.city}
                </Heading>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {props.temperature}°{resolvedUnit}
                  </Text>
                </Row>
              </Stack>
              <Box
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-primary-50, #f0f9ff)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
              >
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Icon name={conditionIcon} size={28} color="var(--ggui-color-primary-700, #0369a1)" />
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-primary-800, #075985)">
                    {props.condition}
                  </Text>
                </Row>
              </Box>
            </Row>

            <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            <Row gap="var(--ggui-spacing-4)" wrap>
              <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="none">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Text size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Text>
                </Stack>
              </Card>
              <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="none">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                  <Text size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} km/h</Text>
                </Stack>
              </Card>
            </Row>

            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                5-Day Forecast
              </Text>
              <Row gap="var(--ggui-spacing-2)" wrap>
                {displayedForecast.map((item, index) => {
                  const dayLabel = item.day || `Day ${index + 1}`;
                  const itemIcon = item.icon || '🌤️';
                  const isSelected = selectedDay === dayLabel;
                  return (
                    <Card
                      key={`${dayLabel}-${index}`}
                      as={Clickable}
                      onClick={() => setSelectedDay(dayLabel)}
                      padding="var(--ggui-spacing-3)"
                      shadow="none"
                      border
                      radius="md"
                    >
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {dayLabel}
                        </Text>
                        <Icon
                          name={itemIcon}
                          size={22}
                          color={isSelected ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        />
                        <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                          {item.high ?? '—'}°{resolvedUnit} / {item.low ?? '—'}°{resolvedUnit}
                        </Text>
                      </Stack>
                    </Card>
                  );
                })}
              </Row>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

