// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });

  const maxComments = 500;
  const totalSteps = 5;

  const emailIsValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && name.trim().length === 0 ? 'Name is required' : '';
  const emailError = touched.email && email.trim().length === 0 ? 'Email is required' : touched.email && !emailIsValid ? 'Enter a valid email address' : '';

  const stepOneValid = name.trim().length > 0 && email.trim().length > 0 && emailIsValid;
  const stepTwoValid = satisfaction >= 1 && satisfaction <= 5;
  const canGoNext = step === 1 ? stepOneValid : step === 2 ? stepTwoValid : true;

  const satisfactionOptions = useMemo(() => {
    return [1, 2, 3, 4, 5].map((rating) => ({
      value: String(rating),
      label: `${rating} - ${props.satisfactionLabels[rating - 1]}`
    }));
  }, [props.satisfactionLabels]);

  const toggleFeature = useCallback((option: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(option)) return prev;
        return [...prev, option];
      }
      return prev.filter((item) => item !== option);
    });
  }, []);

  const goNext = useCallback(() => {
    if (!canGoNext) return;
    setStep((prev) => Math.min(totalSteps, prev + 1));
  }, [canGoNext]);

  const goBack = useCallback(() => {
    setStep((prev) => Math.max(1, prev - 1));
  }, []);

  const onSubmitSurvey = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim()
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          border
          radius="lg"
        >
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Multi-Step Survey</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={(step / totalSteps) * 100} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Contact Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => setName(value)}
                required
                error={nameError}
                placeholder="Enter your full name"
                onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => setEmail(value)}
                required
                error={emailError}
                placeholder="you@example.com"
                onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>

              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction > 0 ? String(satisfaction) : ''}
                onChange={(value) => setSatisfaction(Number(value))}
                options={satisfactionOptions}
                direction="vertical"
                error={satisfaction === 0 ? 'Please select a rating before continuing' : undefined}
              />
            </Stack>

          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select all features you are interested in.
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {(props.featureOptions || []).map((option) => (
                  <Checkbox
                    key={option}
                    label={option}
                    checked={features.includes(option)}
                    onChange={(checked) => toggleFeature(option, checked)}
                  />
                ))}
                {(props.featureOptions || []).length === 0 && (
                  <Alert variant="info" title="No feature options">No features are currently available.</Alert>
                )}
              </Stack>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={(value) => setComments(value.slice(0, maxComments))}
                placeholder="Share any additional thoughts..."
                maxLength={maxComments}
                showCount
                helperText="Maximum 500 characters"
                rows={6}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {comments.length}/{maxComments} characters
              </Text>
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Answers</Heading>
              <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Name</Text>
                  <Text>{name || '—'}</Text>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Text variant="label">Email</Text>
                  <Text>{email || '—'}</Text>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Text variant="label">Satisfaction</Text>
                  <Text>{satisfaction > 0 ? `${satisfaction} - ${props.satisfactionLabels[satisfaction - 1]}` : '—'}</Text>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Text variant="label">Feature Interests</Text>
                  <Text>{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Text variant="label">Comments</Text>
                  <Text>{comments.trim().length > 0 ? comments : 'No additional comments'}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onPress={goBack} disabled={step === 1}>
            Back
          </Button>
          {step < totalSteps ? (
            <Button
              variant="primary"
              onPress={() => {
                if (step === 1) {
                  setTouched({ name: true, email: true });
                }
                goNext();
              }}
              disabled={!canGoNext}
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onPress={onSubmitSurvey}>
              Submit Survey
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

