}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColors = useMemo(() => ({
    'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
    'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition metal': 'var(--ggui-color-info-100, #cffafe)',
    'post-transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    metalloid: 'var(--ggui-color-success-100, #dcfce7)',
    nonmetal: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    halogen: 'var(--ggui-color-warning-200, #fde68a)',
    'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
    'noble-gas': 'var(--ggui-color-primary-200, #bae6fd)',
    lanthanide: 'var(--ggui-color-success-200, #bbf7d0)',
    actinide: 'var(--ggui-color-error-200, #fecaca)',
    unknown: 'var(--ggui-color-outlineVariant, #e4e4e7)',
  }), []);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element, index) => ({
      key: `${element.atomicNumber ?? index}-${element.symbol ?? 'x'}`,
      atomicNumber: element.atomicNumber ?? 0,
      symbol: element.symbol ?? '',
      name: element.name ?? '',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return normalizedElements;
    return normalizedElements.filter((element) => {
      return element.name.toLowerCase().includes(query) || element.symbol.toLowerCase().includes(query);
    });
  }, [normalizedElements, searchQuery]);



  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) ?? null;
  }, [normalizedElements, selectedAtomicNumber]);

  const normalizeCategory = useCallback((category: string) => {
    const base = (category || 'unknown').toLowerCase().trim().replace(/[_]+/g, ' ').replace(/\s+/g, ' ');
    if (base === 'transition') return 'transition metal';
    if (base === 'post transition' || base === 'post transition metal') return 'post-transition metal';
    if (base === 'noble-gas' || base === 'noble gas') return 'noble-gas';
    return base;
  }, []);

  const legendCategories = useMemo(() => {
    return Array.from(new Set(normalizedElements.map((element) => normalizeCategory(element.category || 'unknown'))));
  }, [normalizedElements, normalizeCategory]);

  const getCategoryColor = useCallback(
    (category: string) => {
      const key = normalizeCategory(category);
      return categoryColors[key as keyof typeof categoryColors] ?? 'var(--ggui-color-outlineVariant, #e4e4e7)';
    },
    [categoryColors, normalizeCategory],
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Type name or symbol (e.g., Oxygen, O)"
          value={searchQuery}
          onChange={setSearchQuery}
          helperText="Filter by element name or symbol"
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="warning" title="No data available">
            No element records were provided in props.elements.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)" border shadow="sm">
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-1)',
              }}
            >
              {filteredElements.length === 0 ? (
                <Box style={{ gridColumn: '1 / span 18' }} padding="var(--ggui-spacing-4)">
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No elements match your search.</Text>
                </Box>
              ) : (
                filteredElements.map((element) => (
                  <Card
                    key={element.key}
                    as={Clickable}
                    onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                    padding="var(--ggui-spacing-2)"
                    radius="md"
                    border
                    shadow="none"
                    hoverStyle={{ opacity: 0.9 }}
                    style={{
                      gridColumn: `${element.col}`,
                      gridRow: `${element.row}`,
                      minHeight: '72px',
                      background: getCategoryColor(element.category),
                      borderColor:
                        selectedAtomicNumber === element.atomicNumber
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-outline, #d4d4d8)',
                      borderWidth: selectedAtomicNumber === element.atomicNumber ? '2px' : '1px',
                    }}
                  >
                    <Box
                      style={{
                        position: 'relative',
                        width: '100%',
                        minHeight: '56px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{
                          position: 'absolute',
                          top: '0',
                          left: '0',
                        }}
                      >
                        {element.atomicNumber}
                      </Text>
                      <Text size="xl" weight="bold" align="center" color="var(--ggui-color-onSurface, #18181b)">
                        {element.symbol || '—'}
                      </Text>
                    </Box>
                  </Card>
                ))
              )}
            </Box>
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text weight="semibold" is="span">Name: </Text>{selectedElement.name || 'N/A'}</Text>
                <Text><Text weight="semibold" is="span">Symbol: </Text>{selectedElement.symbol || 'N/A'}</Text>
                <Text><Text weight="semibold" is="span">Atomic Number: </Text>{selectedElement.atomicNumber}</Text>
                <Text><Text weight="semibold" is="span">Atomic Weight: </Text>{selectedElement.atomicWeight}</Text>
                <Text><Text weight="semibold" is="span">Category: </Text>{selectedElement.category}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Select an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-2)">
              {legendCategories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    style={{
                      width: '14px',
                      height: '14px',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
