/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);
  const maxStock = useMemo(() => Math.max(0, props.product?.stock ?? 0), [props.product?.stock]);
  const safeRating = useMemo(() => {
    const raw = props.product?.rating ?? 0;
    return Math.min(5, Math.max(0, Math.round(raw)));
  }, [props.product?.rating]);
  const formattedPrice = useMemo(() => {
    const value = props.product?.price ?? 0;
    const currencyCodeRaw = typeof props.product?.currency === 'string' ? props.product.currency.trim().toUpperCase() : '';
    const currencyCode = /^[A-Z]{3}$/.test(currencyCodeRaw) ? currencyCodeRaw : 'USD';
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency: currencyCode }).format(value);
    } catch {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency: 'USD' }).format(value);
    }
  }, [props.product?.price, props.product?.currency]);
  const specificationsRows = useMemo(() => {
    const list = Array.isArray(props.product?.specifications) ? props.product.specifications : [];
    return list
      .map((item, index) => {
        if (item && typeof item === 'object') {
          const maybe = item as Record<string, unknown>;
          const key = typeof maybe.key === 'string' ? maybe.key : `Spec ${index + 1}`;
          const value = typeof maybe.value === 'string' || typeof maybe.value === 'number' ? String(maybe.value) : '—';
          return { id: `${key}-${index}`, key, value };
        }
        return { id: `spec-${index}`, key: `Spec ${index + 1}`, value: String(item ?? '—') };
      });
  }, [props.product?.specifications]);
  const reviewsList = useMemo(() => {
    const list = Array.isArray(props.product?.reviews) ? props.product.reviews : [];
    return list.map((item, index) => {
      const maybe = item && typeof item === 'object' ? (item as Record<string, unknown>) : {};
      const author = typeof maybe.author === 'string' ? maybe.author : 'Anonymous';
      const text = typeof maybe.text === 'string' ? maybe.text : 'No review text provided.';
      const date = typeof maybe.date === 'string' ? maybe.date : 'Unknown date';
      const rating = typeof maybe.rating === 'number' ? Math.min(5, Math.max(1, Math.round(maybe.rating))) : 1;
      return { id: `${author}-${index}`, author, text, date, rating };
    });
  }, [props.product?.reviews]);
  useEffect(() => {
    if (maxStock <= 0) {
      setQuantity(0);
      return;
    }
    setQuantity((prev) => Math.min(Math.max(1, prev), maxStock));
  }, [maxStock]);
  const incrementQuantity = useCallback(() => {
    if (maxStock <= 0) {
      setQuantity(0);
      return;
    }
    setQuantity((prev) => Math.min(prev + 1, maxStock));
  }, [maxStock]);
  const decrementQuantity = useCallback(() => {
    if (maxStock <= 0) {
      setQuantity(0);
      return;
    }
    setQuantity((prev) => Math.max(1, prev - 1));
  }, [maxStock]);
  const handleQuantityChange = useCallback((value: string) => {
    if (maxStock <= 0) {
      setQuantity(0);
      return;
    }
    const parsed = Number.parseInt(value, 10);
    if (Number.isNaN(parsed)) {
      setQuantity(1);
      return;
    }
    setQuantity(Math.min(Math.max(1, parsed), maxStock));
  }, [maxStock]);
  const handleAddToCart = useCallback(() => {
    if ((props.product?.id ?? '').length === 0 || maxStock <= 0) {
      return;
    }
    addToCart({ productId: props.product?.id ?? '', quantity });
  }, [addToCart, props.product?.id, quantity, maxStock]);

  return (
