                background="var(--ggui-color-primary-100, #e0f2fe)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
              >
                <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                  <Icon name="image" color="var(--ggui-color-primary-700, #0369a1)" size={32} />
                  <Text align="center" weight="semibold" color="var(--ggui-color-primary-800, #075985)">
                    {props.product?.name ?? 'Unnamed Product'}
