                </Stack>
              </Box>
              <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '280px' }}>
                <Heading level={2}>{props.product?.name ?? 'Unnamed Product'}</Heading>
                <Text size="2xl" weight="bold" color="var(--ggui-color-primary-700, #0369a1)">
                  {formattedPrice}
                </Text>
                <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                  <Row gap="var(--ggui-spacing-1)">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <Text key={star} size="lg" color={star <= safeRating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}>
                        ★
                      </Text>
                    ))}
                  </Row>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    ({props.product?.reviewCount ?? reviewsList.length} reviews)
                  </Text>
                </Row>
                <Badge variant={maxStock <= 0 ? 'error' : maxStock > 5 ? 'success' : 'warning'} size="md">
                  {maxStock <= 0 ? 'Out of Stock' : maxStock > 5 ? 'In Stock' : 'Low Stock'}
