                label: 'Description',
                content: (
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text>{props.product?.description ?? 'No description available.'}</Text>
                  </Stack>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
