export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [chatMessages, setChatMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [inputValue, setInputValue] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setChatMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setChatMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [chatMessages.length, typing.latest?.active, typing.latest?.sender]);

  const groupedMessages = useMemo(() => {
    const safeMessages = chatMessages ?? [];
    return safeMessages.reduce<Array<Array<{ sender?: string; text?: string; timestamp?: string }>>>((acc, msg) => {
      if (acc.length === 0) {
        return [[msg]];
      }
      const lastGroup = acc[acc.length - 1];
      const lastSender = lastGroup[lastGroup.length - 1]?.sender ?? '';
      const currentSender = msg?.sender ?? '';
      if (lastSender === currentSender) {
        lastGroup.push(msg);
      } else {
        acc.push([msg]);
      }
      return acc;
    }, []);
  }, [chatMessages]);

  const formatTimestamp = useCallback((timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const now = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp: now });
    setChatMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp: now }]);
