          </Row>
        </Card>

        <Card
          padding="var(--ggui-spacing-4)"
          border
          radius="lg"
          shadow="sm"
        >
          <Stack gap="var(--ggui-spacing-3)">
            <Box
              padding="var(--ggui-spacing-2)"
              background="var(--ggui-color-surface, #fafafa)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{ maxHeight: '60vh', overflowY: 'auto' } as React.CSSProperties}
            >
              <Stack gap="var(--ggui-spacing-2)">
                {groupedMessages.length === 0 ? (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    No messages yet. Start the conversation.
                  </Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const groupSender = group[0]?.sender ?? 'Unknown';
                    const isOwn = groupSender === props.currentUser;
                    return (
                      <Stack key={`${groupSender}-${groupIndex}`} align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{groupSender}</Text>
                        {group.map((msg, msgIndex) => (
                          <Box
                            key={`${groupIndex}-${msgIndex}-${msg.timestamp ?? ''}-${msg.text ?? ''}`}
                            padding="var(--ggui-spacing-2)"
                            background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                            borderRadius="var(--ggui-shape-radius-md, 8px)"
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text
                                variant="bodySmall"
                                color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                              >
                                {msg.text ?? ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={isOwn ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                                align={isOwn ? 'right' : 'left'}
                              >
                                {formatTimestamp(msg.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    );
                  })
                )}
                <Box><div ref={messagesEndRef} /></Box>
              </Stack>
            </Box>

            <Divider margin="var(--ggui-spacing-2)" />

            <Row gap="var(--ggui-spacing-2)" align="end">
              <Box style={{ flex: 1 } as React.CSSProperties}>
                <Input
                  label="Message"
                  placeholder="Type your message"
