                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                />
              </Box>
              <Button
                as={Clickable}
                onClick={handleSend}
                variant="primary"
                disabled={inputValue.trim().length === 0}
              >
                Send
              </Button>
            </Row>
