  const [stockState, setStockState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [now, setNow] = useState<number>(Date.now());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStockState(props.stocks || []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    setStockState((prev) => {
      const next = (prev || []).map((stock) => {
        if (stock.symbol === priceUpdate.latest?.symbol) {
