              >
                {marketStatus.latest?.status || 'live'}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {marketTimestamp ? `Status at ${marketTimestamp}` : `Clock ${new Date(now).toLocaleTimeString()}`}
              </Text>
            </Stack>
          </Row>
        </Card>

        {stockState.length === 0 ? (
          <Card
