              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available
              </Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stockState.map((stock, index) => {
              const isPositive = (stock.change || 0) >= 0;
              const symbol = stock.symbol || `stock-${index}`;
              const isFlashing = !!flashMap[symbol] && now - flashMap[symbol] < 900;
              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-6)"
                  border
                  radius="lg"
                  shadow="sm"
                  style={{
                    background: 'var(--ggui-color-surface, #fafafa)',
                    borderColor: isPositive
                      ? 'var(--ggui-color-success, #16a34a)'
                      : 'var(--ggui-color-error, #dc2626)',
                    boxShadow: isFlashing
                      ? 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))'
                      : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                    animation: isFlashing ? 'ggui-fadeIn 200ms ease-out' : 'none',
                    transition: 'box-shadow 200ms ease, border-color 200ms ease',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      {stock.symbol || '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {stock.name || 'Unknown Company'}
                    </Text>
                    <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />
                    <Row justify="between" align="end">
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
