  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          border
          radius="lg"
        >
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {step === 1 && 'Set up your profile details.'}
              {step === 2 && 'Choose your preferences.'}
              {step === 3 && 'Review and confirm your setup.'}
            </Text>
          </Stack>
        </Card>

        <Box
          padding="var(--ggui-spacing-6)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          style={{
            animation: 'ggui-fadeIn 200ms ease-out',
            transition: 'all 200ms ease-in-out',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
          }}
        >
          <Stack gap="var(--ggui-spacing-6)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={name.trim().length === 0 ? 'Name is required' : ''}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="Enter your email"
                  required
                  error={email.trim().length > 0 && !isEmailValid ? 'Enter a valid email address' : ''}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {(props.avatarOptions.length > 0 ? props.avatarOptions : ['🙂', '🚀', '🎨', '🧠']).map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-2)"
                        radius="md"
                        border
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                          background: avatar === option ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)'
                        }}
                      >
                        <Stack align="center" gap="var(--ggui-spacing-1)">
                          <Text size="2xl">{option}</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {avatar === option ? 'Selected' : 'Select'}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={(props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((r) => ({ value: r, label: r }))}
                  placeholder="Select your role"
                  placeholder="Select your role"
                />
                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(isChecked) => setTheme(isChecked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Text variant="label">Avatar:</Text>
                      <Text>{avatar}</Text>
                    </Row>
                    <Row gap="var(--ggui-spacing-2)"><Text variant="label">Name:</Text><Text>{name}</Text></Row>
                    <Row gap="var(--ggui-spacing-2)"><Text variant="label">Email:</Text><Text>{email}</Text></Row>
                    <Row gap="var(--ggui-spacing-2)"><Text variant="label">Role:</Text><Text>{role}</Text></Row>
                    <Row gap="var(--ggui-spacing-2)"><Text variant="label">Notifications:</Text><Text>{emailNotifications ? 'Enabled' : 'Disabled'}</Text></Row>
                    <Row gap="var(--ggui-spacing-2)"><Text variant="label">Theme:</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Ready to complete">
                  Please confirm the details above, then complete setup.
                </Alert>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
                Back
              </Button>
              <Row gap="var(--ggui-spacing-2)">
                {step < 3 ? (
                  <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                    Next
                  </Button>
                ) : (
                  <>
                    <Button variant="outline" onClick={() => setStep(2)}>
                      Go Back
                    </Button>
                    <Button variant="primary" onClick={handleComplete} disabled={!isStep1Valid}>
                      Complete Setup
                    </Button>
                  </>
                )}
              </Row>
            </Row>
          </Stack>
        </Box>
      </Stack>
    </Container>

  );
}
